import socket
import json
import threading

# Game server configuration
UDP_IP = "0.0.0.0"
UDP_PORT = 12345
MAX_UDP_SIZE = 65507  # Maximum size for a UDP packet
player_list = ["Player1", "Player2", "Player3"]  # Example player list
game_state = {"status": "running", "round": 5}  # Example game state

def send_game_status(addr):
    response = {
        "players": player_list,
        "game_state": game_state
    }
    response_data = json.dumps(response).encode('utf-8')
    if len(response_data) > MAX_UDP_SIZE:
        response_data = response_data[:MAX_UDP_SIZE]  # Truncate if too large
    sock.sendto(response_data, addr)

def handle_requests():
    while True:
        data, addr = sock.recvfrom(1024)  # Buffer size is 1024 bytes
        if data.decode('utf-8') == "status":
            send_game_status(addr)

sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
sock.bind((UDP_IP, UDP_PORT))

print(f"UDP server listening on {UDP_IP}:{UDP_PORT}")

thread = threading.Thread(target=handle_requests)
thread.start()